import React from 'react'
import MainView from './components/main-view/main-view';
import './App.css';

function App() { 
// Check if a specific key exists in localStorage
if (!localStorage.getItem('firstTimeLoad')) {
	// Clear the entire localStorage
	localStorage.clear();
	localStorage.removeItem('encounterID');
	// Set a flag to indicate first time load
	localStorage.setItem('firstTimeLoad', 'true');
  }
	return (
		<div className="App"  >


		<MainView />

		</div>

	)
}

export default App;
